## h1 <- h1 coupling contributions
from . import logger, tools, ascontiguousarray

# CCAA <- CVEA
def compute_sigma_vector__H1__h1_h1__CCAA_CVEA(mr_adc, X_abab, X_baab, sigma):
    cput1 = (logger.process_clock(), logger.perf_counter())

    # Einsum definition from kernel
    einsum = mr_adc.interface.einsum
    einsum_type = mr_adc.interface.einsum_type

    #Excitation Manifold
    ccaa = mr_adc.h1.ccaa

    ## Two-electron integrals
    v_vxae = mr_adc.v2e.vxae
    v_xaev = mr_adc.v2e.xaev

    # Reduced Density Matrices
    rdm_ca = mr_adc.rdm.ca
    rdm_ccaa = mr_adc.rdm.ccaa

    sigma_KLWU =- einsum('KiaU,iLWa->KLWU', X_abab, v_vxae, optimize = einsum_type)
    sigma_KLWU -= einsum('KiaW,LUai->KLWU', X_abab, v_xaev, optimize = einsum_type)
    sigma_KLWU -= einsum('LiaU,KWai->KLWU', X_abab, v_xaev, optimize = einsum_type)
    sigma_KLWU -= einsum('LiaW,iKUa->KLWU', X_abab, v_vxae, optimize = einsum_type)
    sigma_KLWU -= 2 * einsum('KiaW,LUai->KLWU', X_baab, v_xaev, optimize = einsum_type)
    sigma_KLWU += einsum('KiaW,iLUa->KLWU', X_baab, v_vxae, optimize = einsum_type)
    sigma_KLWU -= 2 * einsum('LiaU,KWai->KLWU', X_baab, v_xaev, optimize = einsum_type)
    sigma_KLWU += einsum('LiaU,iKWa->KLWU', X_baab, v_vxae, optimize = einsum_type)
    sigma_KLWU += 1/2 * einsum('KiaU,iLxa,Wx->KLWU', X_abab, v_vxae, rdm_ca, optimize = einsum_type)
    sigma_KLWU += 1/2 * einsum('KiaW,Lxai,Ux->KLWU', X_abab, v_xaev, rdm_ca, optimize = einsum_type)
    sigma_KLWU += 1/2 * einsum('Kiax,LUai,Wx->KLWU', X_abab, v_xaev, rdm_ca, optimize = einsum_type)
    sigma_KLWU -= 1/6 * einsum('Kiax,Lyai,UWxy->KLWU', X_abab, v_xaev, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 1/3 * einsum('Kiax,Lyai,UWyx->KLWU', X_abab, v_xaev, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU += 1/2 * einsum('Kiax,iLWa,Ux->KLWU', X_abab, v_vxae, rdm_ca, optimize = einsum_type)
    sigma_KLWU -= 1/3 * einsum('Kiax,iLya,UWxy->KLWU', X_abab, v_vxae, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 1/6 * einsum('Kiax,iLya,UWyx->KLWU', X_abab, v_vxae, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU += 1/2 * einsum('LiaU,Kxai,Wx->KLWU', X_abab, v_xaev, rdm_ca, optimize = einsum_type)
    sigma_KLWU += 1/2 * einsum('LiaW,iKxa,Ux->KLWU', X_abab, v_vxae, rdm_ca, optimize = einsum_type)
    sigma_KLWU += 1/2 * einsum('Liax,KWai,Ux->KLWU', X_abab, v_xaev, rdm_ca, optimize = einsum_type)
    sigma_KLWU -= 1/3 * einsum('Liax,Kyai,UWxy->KLWU', X_abab, v_xaev, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 1/6 * einsum('Liax,Kyai,UWyx->KLWU', X_abab, v_xaev, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU += 1/2 * einsum('Liax,iKUa,Wx->KLWU', X_abab, v_vxae, rdm_ca, optimize = einsum_type)
    sigma_KLWU -= 1/6 * einsum('Liax,iKya,UWxy->KLWU', X_abab, v_vxae, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 1/3 * einsum('Liax,iKya,UWyx->KLWU', X_abab, v_vxae, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU += einsum('KiaW,Lxai,Ux->KLWU', X_baab, v_xaev, rdm_ca, optimize = einsum_type)
    sigma_KLWU -= 1/2 * einsum('KiaW,iLxa,Ux->KLWU', X_baab, v_vxae, rdm_ca, optimize = einsum_type)
    sigma_KLWU += einsum('Kiax,LUai,Wx->KLWU', X_baab, v_xaev, rdm_ca, optimize = einsum_type)
    sigma_KLWU -= 1/3 * einsum('Kiax,Lyai,UWxy->KLWU', X_baab, v_xaev, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 2/3 * einsum('Kiax,Lyai,UWyx->KLWU', X_baab, v_xaev, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 1/2 * einsum('Kiax,iLUa,Wx->KLWU', X_baab, v_vxae, rdm_ca, optimize = einsum_type)
    sigma_KLWU += 1/6 * einsum('Kiax,iLya,UWxy->KLWU', X_baab, v_vxae, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU += 1/3 * einsum('Kiax,iLya,UWyx->KLWU', X_baab, v_vxae, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU += einsum('LiaU,Kxai,Wx->KLWU', X_baab, v_xaev, rdm_ca, optimize = einsum_type)
    sigma_KLWU -= 1/2 * einsum('LiaU,iKxa,Wx->KLWU', X_baab, v_vxae, rdm_ca, optimize = einsum_type)
    sigma_KLWU += einsum('Liax,KWai,Ux->KLWU', X_baab, v_xaev, rdm_ca, optimize = einsum_type)
    sigma_KLWU -= 2/3 * einsum('Liax,Kyai,UWxy->KLWU', X_baab, v_xaev, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 1/3 * einsum('Liax,Kyai,UWyx->KLWU', X_baab, v_xaev, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 1/2 * einsum('Liax,iKWa,Ux->KLWU', X_baab, v_vxae, rdm_ca, optimize = einsum_type)
    sigma_KLWU += 1/3 * einsum('Liax,iKya,UWxy->KLWU', X_baab, v_vxae, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU += 1/6 * einsum('Liax,iKya,UWyx->KLWU', X_baab, v_vxae, rdm_ccaa, optimize = einsum_type)
    sigma[ccaa] += ascontiguousarray(sigma_KLWU).reshape(-1)

    mr_adc.log.timer_debug("computing sigma H1 h1-h1 CCAA-CVEA", *cput1)

# CCEA <- CVEA
def compute_sigma_vector__H1__h1_h1__CCEA_CVEA(mr_adc, X_abab, X_baab, sigma):
    cput1 = (logger.process_clock(), logger.perf_counter())

    # Einsum definition from kernel
    einsum = mr_adc.interface.einsum
    einsum_type = mr_adc.interface.einsum_type

    #Excitation Manifold
    ccea = mr_adc.h1.ccea

    ## Two-electron integrals
    v_xxxv = mr_adc.v2e.xxxv
    v_xvxx = mr_adc.v2e.xvxx
    v_xvaa = mr_adc.v2e.xvaa
    v_xaav = mr_adc.v2e.xaav
    v_xeev = mr_adc.v2e.xeev
    v_vxee = mr_adc.v2e.vxee

    # Reduced Density Matrices
    rdm_ca = mr_adc.rdm.ca
    rdm_ccaa = mr_adc.rdm.ccaa

    sigma_KLCW  = 2 * einsum('KiCx,LWxi->KLCW', X_abab, v_xaav, optimize = einsum_type)
    sigma_KLCW -= einsum('KiCx,LixW->KLCW', X_abab, v_xvaa, optimize = einsum_type)
    sigma_KLCW -= einsum('KiaW,iLCa->KLCW', X_abab, v_vxee, optimize = einsum_type)
    sigma_KLCW -= einsum('LiaW,KCai->KLCW', X_abab, v_xeev, optimize = einsum_type)
    sigma_KLCW += einsum('ijCW,KiLj->KLCW', X_abab, v_xxxv, optimize = einsum_type)
    sigma_KLCW += einsum('KiCx,LWxi->KLCW', X_baab, v_xaav, optimize = einsum_type)
    sigma_KLCW += einsum('LiCx,KixW->KLCW', X_baab, v_xvaa, optimize = einsum_type)
    sigma_KLCW -= 2 * einsum('LiaW,KCai->KLCW', X_baab, v_xeev, optimize = einsum_type)
    sigma_KLCW += einsum('LiaW,iKCa->KLCW', X_baab, v_vxee, optimize = einsum_type)
    sigma_KLCW -= einsum('ijCW,KjLi->KLCW', X_baab, v_xvxx, optimize = einsum_type)
    sigma_KLCW -= einsum('KiCx,LWyi,xy->KLCW', X_abab, v_xaav, rdm_ca, optimize = einsum_type)
    sigma_KLCW += 1/2 * einsum('KiCx,Lixy,Wy->KLCW', X_abab, v_xvaa, rdm_ca, optimize = einsum_type)
    sigma_KLCW += 1/2 * einsum('KiCx,LiyW,xy->KLCW', X_abab, v_xvaa, rdm_ca, optimize = einsum_type)
    sigma_KLCW += 1/2 * einsum('KiCx,Liyz,Wyxz->KLCW', X_abab, v_xvaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW -= einsum('KiCx,Lyxi,Wy->KLCW', X_abab, v_xaav, rdm_ca, optimize = einsum_type)
    sigma_KLCW += 1/2 * einsum('KiCx,Lyzi,Wzyx->KLCW', X_abab, v_xaav, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW += 1/2 * einsum('Kiax,iLCa,Wx->KLCW', X_abab, v_vxee, rdm_ca, optimize = einsum_type)
    sigma_KLCW += 1/2 * einsum('Liax,KCai,Wx->KLCW', X_abab, v_xeev, rdm_ca, optimize = einsum_type)
    sigma_KLCW -= 1/2 * einsum('ijCx,KiLj,Wx->KLCW', X_abab, v_xxxv, rdm_ca, optimize = einsum_type)
    sigma_KLCW -= 1/2 * einsum('KiCx,LWyi,xy->KLCW', X_baab, v_xaav, rdm_ca, optimize = einsum_type)
    sigma_KLCW -= 1/2 * einsum('KiCx,Lyxi,Wy->KLCW', X_baab, v_xaav, rdm_ca, optimize = einsum_type)
    sigma_KLCW += 1/6 * einsum('KiCx,Lyzi,Wzxy->KLCW', X_baab, v_xaav, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW += 1/3 * einsum('KiCx,Lyzi,Wzyx->KLCW', X_baab, v_xaav, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW -= 1/2 * einsum('LiCx,Kixy,Wy->KLCW', X_baab, v_xvaa, rdm_ca, optimize = einsum_type)
    sigma_KLCW -= 1/2 * einsum('LiCx,KiyW,xy->KLCW', X_baab, v_xvaa, rdm_ca, optimize = einsum_type)
    sigma_KLCW -= 1/2 * einsum('LiCx,Kiyz,Wyxz->KLCW', X_baab, v_xvaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW += 1/3 * einsum('LiCx,Kyzi,Wzxy->KLCW', X_baab, v_xaav, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW += 1/6 * einsum('LiCx,Kyzi,Wzyx->KLCW', X_baab, v_xaav, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW += einsum('Liax,KCai,Wx->KLCW', X_baab, v_xeev, rdm_ca, optimize = einsum_type)
    sigma_KLCW -= 1/2 * einsum('Liax,iKCa,Wx->KLCW', X_baab, v_vxee, rdm_ca, optimize = einsum_type)
    sigma_KLCW += 1/2 * einsum('ijCx,KjLi,Wx->KLCW', X_baab, v_xvxx, rdm_ca, optimize = einsum_type)
    sigma_KLCW -= 1/2 * einsum('KiCx,Liyz,yz,Wx->KLCW', X_abab, v_xvaa, rdm_ca, rdm_ca, optimize = einsum_type)
    sigma_KLCW += 1/4 * einsum('KiCx,Lyzi,zy,Wx->KLCW', X_abab, v_xaav, rdm_ca, rdm_ca, optimize = einsum_type)
    sigma_KLCW += 1/2 * einsum('LiCx,Kiyz,yz,Wx->KLCW', X_baab, v_xvaa, rdm_ca, rdm_ca, optimize = einsum_type)
    sigma_KLCW -= 1/4 * einsum('LiCx,Kyzi,zy,Wx->KLCW', X_baab, v_xaav, rdm_ca, rdm_ca, optimize = einsum_type)
    sigma[ccea] += ascontiguousarray(sigma_KLCW).reshape(-1)

    mr_adc.log.timer_debug("computing sigma H1 h1-h1 CCEA-CVEA", *cput1)

# CCEE <- CVEA
def compute_sigma_vector__H1__h1_h1__CCEE_CVEA(mr_adc, X_abab, X_baab, sigma):
    cput1 = (logger.process_clock(), logger.perf_counter())

    # Einsum definition from kernel
    einsum = mr_adc.interface.einsum
    einsum_type = mr_adc.interface.einsum_type

    #Excitation Manifold
    ccee = mr_adc.h1.ccee

    ## Two-electron integrals
    v_xvae = mr_adc.v2e.xvae
    v_vaex = mr_adc.v2e.vaex
     
    # Reduced Density Matrices
    rdm_ca = mr_adc.rdm.ca

    sigma_KLCD =- einsum('KiCx,LixD->KLCD', X_abab, v_xvae, optimize = einsum_type)
    sigma_KLCD += 2 * einsum('KiCx,ixDL->KLCD', X_abab, v_vaex, optimize = einsum_type)
    sigma_KLCD -= einsum('LiDx,KixC->KLCD', X_abab, v_xvae, optimize = einsum_type)
    sigma_KLCD += 2 * einsum('LiDx,ixCK->KLCD', X_abab, v_vaex, optimize = einsum_type)
    sigma_KLCD += einsum('KiCx,ixDL->KLCD', X_baab, v_vaex, optimize = einsum_type)
    sigma_KLCD += einsum('KiDx,LixC->KLCD', X_baab, v_xvae, optimize = einsum_type)
    sigma_KLCD += einsum('LiCx,KixD->KLCD', X_baab, v_xvae, optimize = einsum_type)
    sigma_KLCD += einsum('LiDx,ixCK->KLCD', X_baab, v_vaex, optimize = einsum_type)
    sigma_KLCD += 1/2 * einsum('KiCx,LiyD,xy->KLCD', X_abab, v_xvae, rdm_ca, optimize = einsum_type)
    sigma_KLCD -= einsum('KiCx,iyDL,xy->KLCD', X_abab, v_vaex, rdm_ca, optimize = einsum_type)
    sigma_KLCD += 1/2 * einsum('LiDx,KiyC,xy->KLCD', X_abab, v_xvae, rdm_ca, optimize = einsum_type)
    sigma_KLCD -= einsum('LiDx,iyCK,xy->KLCD', X_abab, v_vaex, rdm_ca, optimize = einsum_type)
    sigma_KLCD -= 1/2 * einsum('KiCx,iyDL,xy->KLCD', X_baab, v_vaex, rdm_ca, optimize = einsum_type)
    sigma_KLCD -= 1/2 * einsum('KiDx,LiyC,xy->KLCD', X_baab, v_xvae, rdm_ca, optimize = einsum_type)
    sigma_KLCD -= 1/2 * einsum('LiCx,KiyD,xy->KLCD', X_baab, v_xvae, rdm_ca, optimize = einsum_type)
    sigma_KLCD -= 1/2 * einsum('LiDx,iyCK,xy->KLCD', X_baab, v_vaex, rdm_ca, optimize = einsum_type)
    sigma[ccee] += ascontiguousarray(sigma_KLCD).reshape(-1)

    mr_adc.log.timer_debug("computing sigma H1 h1-h1 CCEE-CVEA", *cput1)
    
# CAEE <- CVEA
def compute_sigma_vector__H1__h1_h1__CAEE_CVEA(mr_adc, X_abab, X_baab, sigma):
    cput1 = (logger.process_clock(), logger.perf_counter())

    # Einsum definition from kernel
    einsum = mr_adc.interface.einsum
    einsum_type = mr_adc.interface.einsum_type

    #Excitation Manifold
    caee = mr_adc.h1.caee

    ## Two-electron integrals
    v_vaea = mr_adc.v2e.vaea

    # Reduced Density Matrices
    rdm_ca = mr_adc.rdm.ca
    rdm_ccaa = mr_adc.rdm.ccaa

    sigma_KWCD  = einsum('KiCx,ixDy,Wy->KWCD', X_abab, v_vaea, rdm_ca, optimize = einsum_type)
    sigma_KWCD -= 1/2 * einsum('KiCx,iyDx,Wy->KWCD', X_abab, v_vaea, rdm_ca, optimize = einsum_type)
    sigma_KWCD -= 1/2 * einsum('KiCx,iyDz,Wxzy->KWCD', X_abab, v_vaea, rdm_ccaa, optimize = einsum_type)
    sigma_KWCD += 1/2 * einsum('KiCx,ixDy,Wy->KWCD', X_baab, v_vaea, rdm_ca, optimize = einsum_type)
    sigma_KWCD -= 1/6 * einsum('KiCx,iyDz,Wxyz->KWCD', X_baab, v_vaea, rdm_ccaa, optimize = einsum_type)
    sigma_KWCD -= 1/3 * einsum('KiCx,iyDz,Wxzy->KWCD', X_baab, v_vaea, rdm_ccaa, optimize = einsum_type)
    sigma_KWCD += 1/2 * einsum('KiDx,iyCx,Wy->KWCD', X_baab, v_vaea, rdm_ca, optimize = einsum_type)
    sigma_KWCD -= 1/3 * einsum('KiDx,iyCz,Wxyz->KWCD', X_baab, v_vaea, rdm_ccaa, optimize = einsum_type)
    sigma_KWCD -= 1/6 * einsum('KiDx,iyCz,Wxzy->KWCD', X_baab, v_vaea, rdm_ccaa, optimize = einsum_type)
    sigma[caee] += ascontiguousarray(sigma_KWCD).reshape(-1)

    mr_adc.log.timer_debug("computing sigma H1 h1-h1 CAEE-CVEA", *cput1)

# CAAA <- CVEA
def compute_sigma_vector__H1__h1_h1__CAAA_CVEA(mr_adc, X_abab, X_baab, sigma):
    cput1 = (logger.process_clock(), logger.perf_counter())

    # Einsum definition from kernel
    einsum = mr_adc.interface.einsum
    einsum_type = mr_adc.interface.einsum_type

    # Excitation Manifold
    caaa__aaaa = mr_adc.h1.caaa__aaaa
    caaa__abab = mr_adc.h1.caaa__abab

    ## Indices
    aa_tril_ind = mr_adc.h1.aa_tril_ind 

    ## Molecular Orbitals Energies
    e_val = mr_adc.mo_energy.v
    e_extern = mr_adc.mo_energy.e
    
    ## One-electron integrals
    h_aa = mr_adc.h1eff.aa

    ## Two-electron integrals
    v_xxve = mr_adc.v2e.xxve
    v_vxxe = mr_adc.v2e.vxxe
    v_vaae = mr_adc.v2e.vaae
    v_veaa = mr_adc.v2e.veaa
    v_aaaa = mr_adc.v2e.aaaa

    ## Amplitudes
    t1_vaae = mr_adc.t1.vaae 
    t1_vaea = mr_adc.t1.vaea

    # Reduced Density Matrices
    rdm_ca = mr_adc.rdm.ca
    rdm_ccaa = mr_adc.rdm.ccaa
    rdm_cccaaa = mr_adc.rdm.cccaaa

    sigma_KWUV_aaaa =- 1/2 * einsum('KiaU,iWxa,Vx->KWUV', X_abab, v_vaae, rdm_ca, optimize = einsum_type)
    sigma_KWUV_aaaa -= 1/2 * einsum('KiaU,iaVx,Wx->KWUV', X_abab, v_veaa, rdm_ca, optimize = einsum_type)
    sigma_KWUV_aaaa += 1/2 * einsum('KiaU,iaxW,Vx->KWUV', X_abab, v_veaa, rdm_ca, optimize = einsum_type)
    sigma_KWUV_aaaa += 1/2 * einsum('KiaU,ixVa,Wx->KWUV', X_abab, v_vaae, rdm_ca, optimize = einsum_type)
    sigma_KWUV_aaaa += 1/2 * einsum('KiaV,iWxa,Ux->KWUV', X_abab, v_vaae, rdm_ca, optimize = einsum_type)
    sigma_KWUV_aaaa += 1/2 * einsum('KiaV,iaUx,Wx->KWUV', X_abab, v_veaa, rdm_ca, optimize = einsum_type)
    sigma_KWUV_aaaa -= 1/2 * einsum('KiaV,iaxW,Ux->KWUV', X_abab, v_veaa, rdm_ca, optimize = einsum_type)
    sigma_KWUV_aaaa -= 1/2 * einsum('KiaV,ixUa,Wx->KWUV', X_abab, v_vaae, rdm_ca, optimize = einsum_type)
    sigma_KWUV_aaaa += 1/6 * einsum('Kiax,iWya,UVxy->KWUV', X_abab, v_vaae, rdm_ccaa, optimize = einsum_type)
    sigma_KWUV_aaaa -= 1/6 * einsum('Kiax,iWya,UVyx->KWUV', X_abab, v_vaae, rdm_ccaa, optimize = einsum_type)
    sigma_KWUV_aaaa -= 1/2 * einsum('Kiax,iaUx,VW->KWUV', X_abab, v_veaa, rdm_ca, optimize = einsum_type)
    sigma_KWUV_aaaa += 1/6 * einsum('Kiax,iaUy,VyWx->KWUV', X_abab, v_veaa, rdm_ccaa, optimize = einsum_type)
    sigma_KWUV_aaaa -= 1/6 * einsum('Kiax,iaUy,VyxW->KWUV', X_abab, v_veaa, rdm_ccaa, optimize = einsum_type)
    sigma_KWUV_aaaa += 1/2 * einsum('Kiax,iaVx,UW->KWUV', X_abab, v_veaa, rdm_ca, optimize = einsum_type)
    sigma_KWUV_aaaa -= 1/6 * einsum('Kiax,iaVy,UyWx->KWUV', X_abab, v_veaa, rdm_ccaa, optimize = einsum_type)
    sigma_KWUV_aaaa += 1/6 * einsum('Kiax,iaVy,UyxW->KWUV', X_abab, v_veaa, rdm_ccaa, optimize = einsum_type)
    sigma_KWUV_aaaa -= 1/6 * einsum('Kiax,iayW,UVxy->KWUV', X_abab, v_veaa, rdm_ccaa, optimize = einsum_type)
    sigma_KWUV_aaaa += 1/6 * einsum('Kiax,iayW,UVyx->KWUV', X_abab, v_veaa, rdm_ccaa, optimize = einsum_type)
    sigma_KWUV_aaaa += einsum('Kiax,ixUa,VW->KWUV', X_abab, v_vaae, rdm_ca, optimize = einsum_type)
    sigma_KWUV_aaaa -= einsum('Kiax,ixVa,UW->KWUV', X_abab, v_vaae, rdm_ca, optimize = einsum_type)
