    sigma_KLWU += 1/6 * einsum('KLax,yzwa,Wuwv,Uuvyzx->KLWU', X_baab, t1_aaae, v_aaaa, rdm_cccaaa, optimize = einsum_type)
    sigma_KLWU -= 1/6 * einsum('KLax,yzwa,Wuwv,Uuvzxy->KLWU', X_baab, t1_aaae, v_aaaa, rdm_cccaaa, optimize = einsum_type)
    sigma_KLWU += 1/6 * einsum('KLax,yzwa,Wuwv,Uuvzyx->KLWU', X_baab, t1_aaae, v_aaaa, rdm_cccaaa, optimize = einsum_type)
    sigma_KLWU -= 1/6 * einsum('KLax,yzwa,Wuwx,Uuyz->KLWU', X_baab, t1_aaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 1/3 * einsum('KLax,yzwa,Wuwx,Uuzy->KLWU', X_baab, t1_aaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 1/2 * einsum('KLax,yzwa,Wxuy,Uwzu->KLWU', X_baab, t1_aaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 1/2 * einsum('KLax,yzwa,Wxuz,Uwuy->KLWU', X_baab, t1_aaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU += 1/2 * einsum('KLax,yzwa,Wxwu,Uuzy->KLWU', X_baab, t1_aaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 1/6 * einsum('KLax,yzwa,Wyuv,Uwvuxz->KLWU', X_baab, t1_aaae, v_aaaa, rdm_cccaaa, optimize = einsum_type)
    sigma_KLWU -= 1/6 * einsum('KLax,yzwa,Wyuv,Uwvuzx->KLWU', X_baab, t1_aaae, v_aaaa, rdm_cccaaa, optimize = einsum_type)
