    sigma_KLWU += 1/6 * einsum('KLax,yzwa,Wyuv,Uwvzxu->KLWU', X_baab, t1_aaae, v_aaaa, rdm_cccaaa, optimize = einsum_type)
    sigma_KLWU += 1/6 * einsum('KLax,yzwa,Wyux,Uwuz->KLWU', X_baab, t1_aaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU += 1/3 * einsum('KLax,yzwa,Wyux,Uwzu->KLWU', X_baab, t1_aaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
