# CVEA <- CVEA
def compute_sigma_vector__H1__h1_h1__CVEA_CVEA(mr_adc, X_abab, X_baab, sigma):
    cput1 = (logger.process_clock(), logger.perf_counter())

    # Einsum definition from kernel
    einsum = mr_adc.interface.einsum
    einsum_type = mr_adc.interface.einsum_type

    #Excitation Manifold
    cvea__abab = mr_adc.h1.cvea__abab
    cvea__baab = mr_adc.h1.cvea__baab

    ## Two-electron integrals
    v_xxvv = mr_adc.v2e.xxvv
    v_xxaa = mr_adc.v2e.xxaa
    v_xxee = mr_adc.v2e.xxee
    v_xvvx = mr_adc.v2e.xvvx
    v_xaax = mr_adc.v2e.xaax
    v_xeex = mr_adc.v2e.xeex
    v_vvaa = mr_adc.v2e.vvaa
    v_vvee = mr_adc.v2e.vvee
    v_vaav = mr_adc.v2e.vaav
    v_veev = mr_adc.v2e.veev
    v_aaee = mr_adc.v2e.aaee
    v_aeea = mr_adc.v2e.aeea

    # Reduced Density Matrices
    rdm_ca = mr_adc.rdm.ca
    rdm_ccaa = mr_adc.rdm.ccaa

    sigma_KLCW_abab  = einsum('KLax,WxCa->KLCW', X_abab, v_aaee, optimize = einsum_type)
    sigma_KLCW_abab += 2 * einsum('KiCx,LWxi->KLCW', X_abab, v_vaav, optimize = einsum_type)
    sigma_KLCW_abab -= einsum('KiCx,LixW->KLCW', X_abab, v_vvaa, optimize = einsum_type)
    sigma_KLCW_abab -= einsum('KiaW,iLCa->KLCW', X_abab, v_vvee, optimize = einsum_type)
    sigma_KLCW_abab -= einsum('iLCx,KixW->KLCW', X_abab, v_xxaa, optimize = einsum_type)
    sigma_KLCW_abab += 2 * einsum('iLaW,KCai->KLCW', X_abab, v_xeex, optimize = einsum_type)
    sigma_KLCW_abab -= einsum('iLaW,iKCa->KLCW', X_abab, v_xxee, optimize = einsum_type)
    sigma_KLCW_abab += einsum('ijCW,KiLj->KLCW', X_abab, v_xxvv, optimize = einsum_type)
    sigma_KLCW_abab -= einsum('KLax,xCaW->KLCW', X_baab, v_aeea, optimize = einsum_type)
    sigma_KLCW_abab += einsum('KiCx,LWxi->KLCW', X_baab, v_vaav, optimize = einsum_type)
    sigma_KLCW_abab += einsum('iLaW,KCai->KLCW', X_baab, v_xeex, optimize = einsum_type)
    sigma_KLCW_abab -= einsum('ijCW,KjLi->KLCW', X_baab, v_xvvx, optimize = einsum_type)
    sigma_KLCW_abab -= 1/2 * einsum('KLax,WyCa,xy->KLCW', X_abab, v_aaee, rdm_ca, optimize = einsum_type)
    sigma_KLCW_abab += 1/3 * einsum('KLax,yCaz,Wyxz->KLCW', X_abab, v_aeea, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW_abab += 1/6 * einsum('KLax,yCaz,Wyzx->KLCW', X_abab, v_aeea, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW_abab -= 1/2 * einsum('KLax,yxCa,Wy->KLCW', X_abab, v_aaee, rdm_ca, optimize = einsum_type)
    sigma_KLCW_abab -= 1/2 * einsum('KLax,yzCa,Wzxy->KLCW', X_abab, v_aaee, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW_abab -= einsum('KiCx,LWyi,xy->KLCW', X_abab, v_vaav, rdm_ca, optimize = einsum_type)
    sigma_KLCW_abab += 1/2 * einsum('KiCx,Lixy,Wy->KLCW', X_abab, v_vvaa, rdm_ca, optimize = einsum_type)
    sigma_KLCW_abab += 1/2 * einsum('KiCx,LiyW,xy->KLCW', X_abab, v_vvaa, rdm_ca, optimize = einsum_type)
    sigma_KLCW_abab += 1/2 * einsum('KiCx,Liyz,Wyxz->KLCW', X_abab, v_vvaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW_abab -= einsum('KiCx,Lyxi,Wy->KLCW', X_abab, v_vaav, rdm_ca, optimize = einsum_type)
    sigma_KLCW_abab += 1/2 * einsum('KiCx,Lyzi,Wzyx->KLCW', X_abab, v_vaav, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW_abab += 1/2 * einsum('Kiax,iLCa,Wx->KLCW', X_abab, v_vvee, rdm_ca, optimize = einsum_type)
    sigma_KLCW_abab += 1/2 * einsum('iLCx,Kixy,Wy->KLCW', X_abab, v_xxaa, rdm_ca, optimize = einsum_type)
    sigma_KLCW_abab += 1/2 * einsum('iLCx,KiyW,xy->KLCW', X_abab, v_xxaa, rdm_ca, optimize = einsum_type)
    sigma_KLCW_abab += 1/2 * einsum('iLCx,Kiyz,Wyxz->KLCW', X_abab, v_xxaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW_abab -= 1/3 * einsum('iLCx,Kyzi,Wzxy->KLCW', X_abab, v_xaax, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW_abab -= 1/6 * einsum('iLCx,Kyzi,Wzyx->KLCW', X_abab, v_xaax, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW_abab -= einsum('iLax,KCai,Wx->KLCW', X_abab, v_xeex, rdm_ca, optimize = einsum_type)
    sigma_KLCW_abab += 1/2 * einsum('iLax,iKCa,Wx->KLCW', X_abab, v_xxee, rdm_ca, optimize = einsum_type)
    sigma_KLCW_abab -= 1/2 * einsum('ijCx,KiLj,Wx->KLCW', X_abab, v_xxvv, rdm_ca, optimize = einsum_type)
    sigma_KLCW_abab += 1/2 * einsum('KLax,xCay,Wy->KLCW', X_baab, v_aeea, rdm_ca, optimize = einsum_type)
    sigma_KLCW_abab += 1/2 * einsum('KLax,yCaW,xy->KLCW', X_baab, v_aeea, rdm_ca, optimize = einsum_type)
    sigma_KLCW_abab -= 1/6 * einsum('KLax,yCaz,Wyxz->KLCW', X_baab, v_aeea, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW_abab -= 1/3 * einsum('KLax,yCaz,Wyzx->KLCW', X_baab, v_aeea, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW_abab -= 1/2 * einsum('KiCx,LWyi,xy->KLCW', X_baab, v_vaav, rdm_ca, optimize = einsum_type)
    sigma_KLCW_abab -= 1/2 * einsum('KiCx,Lyxi,Wy->KLCW', X_baab, v_vaav, rdm_ca, optimize = einsum_type)
    sigma_KLCW_abab += 1/6 * einsum('KiCx,Lyzi,Wzxy->KLCW', X_baab, v_vaav, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW_abab += 1/3 * einsum('KiCx,Lyzi,Wzyx->KLCW', X_baab, v_vaav, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW_abab -= 1/2 * einsum('iLax,KCai,Wx->KLCW', X_baab, v_xeex, rdm_ca, optimize = einsum_type)
    sigma_KLCW_abab += 1/2 * einsum('ijCx,KjLi,Wx->KLCW', X_baab, v_xvvx, rdm_ca, optimize = einsum_type)
    sigma_KLCW_abab -= 1/4 * einsum('KLax,yCaz,zy,Wx->KLCW', X_abab, v_aeea, rdm_ca, rdm_ca, optimize = einsum_type)
    sigma_KLCW_abab += 1/2 * einsum('KLax,yzCa,yz,Wx->KLCW', X_abab, v_aaee, rdm_ca, rdm_ca, optimize = einsum_type)
    sigma_KLCW_abab -= 1/2 * einsum('KiCx,Liyz,yz,Wx->KLCW', X_abab, v_vvaa, rdm_ca, rdm_ca, optimize = einsum_type)
    sigma_KLCW_abab += 1/4 * einsum('KiCx,Lyzi,zy,Wx->KLCW', X_abab, v_vaav, rdm_ca, rdm_ca, optimize = einsum_type)
    sigma_KLCW_abab -= 1/2 * einsum('iLCx,Kiyz,yz,Wx->KLCW', X_abab, v_xxaa, rdm_ca, rdm_ca, optimize = einsum_type)
    sigma_KLCW_abab += 1/4 * einsum('iLCx,Kyzi,zy,Wx->KLCW', X_abab, v_xaax, rdm_ca, rdm_ca, optimize = einsum_type)
    sigma[cvea__abab] += ascontiguousarray(sigma_KLCW_abab).reshape(-1)

    sigma_KLCW_baab =- einsum('KLax,xCaW->KLCW', X_abab, v_aeea, optimize = einsum_type)
    sigma_KLCW_baab += einsum('KiaW,LCai->KLCW', X_abab, v_veev, optimize = einsum_type)
    sigma_KLCW_baab += einsum('iLCx,KWxi->KLCW', X_abab, v_xaax, optimize = einsum_type)
    sigma_KLCW_baab -= einsum('ijCW,KjLi->KLCW', X_abab, v_xvvx, optimize = einsum_type)
    sigma_KLCW_baab += einsum('KLax,WxCa->KLCW', X_baab, v_aaee, optimize = einsum_type)
    sigma_KLCW_baab -= einsum('KiCx,LixW->KLCW', X_baab, v_vvaa, optimize = einsum_type)
    sigma_KLCW_baab += 2 * einsum('KiaW,LCai->KLCW', X_baab, v_veev, optimize = einsum_type)
    sigma_KLCW_baab -= einsum('KiaW,iLCa->KLCW', X_baab, v_vvee, optimize = einsum_type)
    sigma_KLCW_baab += 2 * einsum('iLCx,KWxi->KLCW', X_baab, v_xaax, optimize = einsum_type)
    sigma_KLCW_baab -= einsum('iLCx,KixW->KLCW', X_baab, v_xxaa, optimize = einsum_type)
    sigma_KLCW_baab -= einsum('iLaW,iKCa->KLCW', X_baab, v_xxee, optimize = einsum_type)
    sigma_KLCW_baab += einsum('ijCW,KiLj->KLCW', X_baab, v_xxvv, optimize = einsum_type)
    sigma_KLCW_baab += 1/2 * einsum('KLax,xCay,Wy->KLCW', X_abab, v_aeea, rdm_ca, optimize = einsum_type)
    sigma_KLCW_baab += 1/2 * einsum('KLax,yCaW,xy->KLCW', X_abab, v_aeea, rdm_ca, optimize = einsum_type)
    sigma_KLCW_baab -= 1/6 * einsum('KLax,yCaz,Wyxz->KLCW', X_abab, v_aeea, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW_baab -= 1/3 * einsum('KLax,yCaz,Wyzx->KLCW', X_abab, v_aeea, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW_baab -= 1/2 * einsum('Kiax,LCai,Wx->KLCW', X_abab, v_veev, rdm_ca, optimize = einsum_type)
    sigma_KLCW_baab -= 1/2 * einsum('iLCx,KWyi,xy->KLCW', X_abab, v_xaax, rdm_ca, optimize = einsum_type)
    sigma_KLCW_baab -= 1/2 * einsum('iLCx,Kyxi,Wy->KLCW', X_abab, v_xaax, rdm_ca, optimize = einsum_type)
    sigma_KLCW_baab += 1/6 * einsum('iLCx,Kyzi,Wzxy->KLCW', X_abab, v_xaax, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW_baab += 1/3 * einsum('iLCx,Kyzi,Wzyx->KLCW', X_abab, v_xaax, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW_baab += 1/2 * einsum('ijCx,KjLi,Wx->KLCW', X_abab, v_xvvx, rdm_ca, optimize = einsum_type)
    sigma_KLCW_baab -= 1/2 * einsum('KLax,WyCa,xy->KLCW', X_baab, v_aaee, rdm_ca, optimize = einsum_type)
    sigma_KLCW_baab += 1/3 * einsum('KLax,yCaz,Wyxz->KLCW', X_baab, v_aeea, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW_baab += 1/6 * einsum('KLax,yCaz,Wyzx->KLCW', X_baab, v_aeea, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW_baab -= 1/2 * einsum('KLax,yxCa,Wy->KLCW', X_baab, v_aaee, rdm_ca, optimize = einsum_type)
    sigma_KLCW_baab -= 1/2 * einsum('KLax,yzCa,Wzxy->KLCW', X_baab, v_aaee, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW_baab += 1/2 * einsum('KiCx,Lixy,Wy->KLCW', X_baab, v_vvaa, rdm_ca, optimize = einsum_type)
    sigma_KLCW_baab += 1/2 * einsum('KiCx,LiyW,xy->KLCW', X_baab, v_vvaa, rdm_ca, optimize = einsum_type)
    sigma_KLCW_baab += 1/2 * einsum('KiCx,Liyz,Wyxz->KLCW', X_baab, v_vvaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW_baab -= 1/3 * einsum('KiCx,Lyzi,Wzxy->KLCW', X_baab, v_vaav, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW_baab -= 1/6 * einsum('KiCx,Lyzi,Wzyx->KLCW', X_baab, v_vaav, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW_baab -= einsum('Kiax,LCai,Wx->KLCW', X_baab, v_veev, rdm_ca, optimize = einsum_type)
    sigma_KLCW_baab += 1/2 * einsum('Kiax,iLCa,Wx->KLCW', X_baab, v_vvee, rdm_ca, optimize = einsum_type)
    sigma_KLCW_baab -= einsum('iLCx,KWyi,xy->KLCW', X_baab, v_xaax, rdm_ca, optimize = einsum_type)
    sigma_KLCW_baab += 1/2 * einsum('iLCx,Kixy,Wy->KLCW', X_baab, v_xxaa, rdm_ca, optimize = einsum_type)
    sigma_KLCW_baab += 1/2 * einsum('iLCx,KiyW,xy->KLCW', X_baab, v_xxaa, rdm_ca, optimize = einsum_type)
    sigma_KLCW_baab += 1/2 * einsum('iLCx,Kiyz,Wyxz->KLCW', X_baab, v_xxaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW_baab -= einsum('iLCx,Kyxi,Wy->KLCW', X_baab, v_xaax, rdm_ca, optimize = einsum_type)
    sigma_KLCW_baab += 1/2 * einsum('iLCx,Kyzi,Wzyx->KLCW', X_baab, v_xaax, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW_baab += 1/2 * einsum('iLax,iKCa,Wx->KLCW', X_baab, v_xxee, rdm_ca, optimize = einsum_type)
    sigma_KLCW_baab -= 1/2 * einsum('ijCx,KiLj,Wx->KLCW', X_baab, v_xxvv, rdm_ca, optimize = einsum_type)
    sigma_KLCW_baab -= 1/4 * einsum('KLax,yCaz,zy,Wx->KLCW', X_baab, v_aeea, rdm_ca, rdm_ca, optimize = einsum_type)
    sigma_KLCW_baab += 1/2 * einsum('KLax,yzCa,yz,Wx->KLCW', X_baab, v_aaee, rdm_ca, rdm_ca, optimize = einsum_type)
    sigma_KLCW_baab -= 1/2 * einsum('KiCx,Liyz,yz,Wx->KLCW', X_baab, v_vvaa, rdm_ca, rdm_ca, optimize = einsum_type)
    sigma_KLCW_baab += 1/4 * einsum('KiCx,Lyzi,zy,Wx->KLCW', X_baab, v_vaav, rdm_ca, rdm_ca, optimize = einsum_type)
    sigma_KLCW_baab -= 1/2 * einsum('iLCx,Kiyz,yz,Wx->KLCW', X_baab, v_xxaa, rdm_ca, rdm_ca, optimize = einsum_type)
    sigma_KLCW_baab += 1/4 * einsum('iLCx,Kyzi,zy,Wx->KLCW', X_baab, v_xaax, rdm_ca, rdm_ca, optimize = einsum_type)
    sigma[cvea__baab] += ascontiguousarray(sigma_KLCW_baab).reshape(-1)

    mr_adc.log.timer_debug("computing sigma H1 h1-h1 CVEA-CVEA", *cput1)

# CVEE <- CVEA
def compute_sigma_vector__H1__h1_h1__CVEE_CVEA(mr_adc, X_abab, X_baab, sigma):        
    cput1 = (logger.process_clock(), logger.perf_counter())

    # Einsum definition from kernel
    einsum = mr_adc.interface.einsum
    einsum_type = mr_adc.interface.einsum_type

    #Excitation Manifold
    cvee = mr_adc.h1.cvee

    ## Molecular Orbitals Energies
    e_extern = mr_adc.mo_energy.e
    
    ## One-electron integrals
    h_aa = mr_adc.h1eff.aa
    h_ae = mr_adc.h1eff.ae

    ## Two-electron integrals
    v_xxae = mr_adc.v2e.xxae
    v_xaex = mr_adc.v2e.xaex
    v_vvae = mr_adc.v2e.vvae
    v_vaev = mr_adc.v2e.vaev
    v_aaaa = mr_adc.v2e.aaaa
    v_aaae = mr_adc.v2e.aaae
    v_aeee = mr_adc.v2e.aeee

    ## Amplitudes
    t1_ae = mr_adc.t1.ae
    t1_aaae = mr_adc.t1.aaae
    
    # Reduced Density Matrices
    rdm_ca = mr_adc.rdm.ca
    rdm_ccaa = mr_adc.rdm.ccaa

    sigma_KLCD  = einsum('KLCx,xD->KLCD', X_abab, h_ae, optimize = einsum_type)
    sigma_KLCD += einsum('KLax,xDaC->KLCD', X_abab, v_aeee, optimize = einsum_type)
    sigma_KLCD -= einsum('KiCx,LixD->KLCD', X_abab, v_vvae, optimize = einsum_type)
    sigma_KLCD += 2 * einsum('KiCx,ixDL->KLCD', X_abab, v_vaev, optimize = einsum_type)
    sigma_KLCD -= einsum('iLCx,KixD->KLCD', X_abab, v_xxae, optimize = einsum_type)
    sigma_KLCD -= einsum('iLDx,ixCK->KLCD', X_abab, v_xaex, optimize = einsum_type)
    sigma_KLCD -= einsum('KLDx,xC->KLCD', X_baab, h_ae, optimize = einsum_type)
    sigma_KLCD -= einsum('KLax,xCaD->KLCD', X_baab, v_aeee, optimize = einsum_type)
    sigma_KLCD += einsum('KiCx,ixDL->KLCD', X_baab, v_vaev, optimize = einsum_type)
    sigma_KLCD += einsum('KiDx,LixC->KLCD', X_baab, v_vvae, optimize = einsum_type)
    sigma_KLCD += einsum('iLDx,KixC->KLCD', X_baab, v_xxae, optimize = einsum_type)
    sigma_KLCD -= 2 * einsum('iLDx,ixCK->KLCD', X_baab, v_xaex, optimize = einsum_type)
    sigma_KLCD += einsum('KLCx,D,xD->KLCD', X_abab, e_extern, t1_ae, optimize = einsum_type)
    sigma_KLCD -= einsum('KLCx,xy,yD->KLCD', X_abab, h_aa, t1_ae, optimize = einsum_type)
    sigma_KLCD -= 1/2 * einsum('KLCx,xyzD,yz->KLCD', X_abab, v_aaae, rdm_ca, optimize = einsum_type)
    sigma_KLCD += einsum('KLCx,yzxD,zy->KLCD', X_abab, v_aaae, rdm_ca, optimize = einsum_type)
    sigma_KLCD -= 1/2 * einsum('KLax,yDaC,xy->KLCD', X_abab, v_aeee, rdm_ca, optimize = einsum_type)
    sigma_KLCD += 1/2 * einsum('KiCx,LiyD,xy->KLCD', X_abab, v_vvae, rdm_ca, optimize = einsum_type)
    sigma_KLCD -= einsum('KiCx,iyDL,xy->KLCD', X_abab, v_vaev, rdm_ca, optimize = einsum_type)
    sigma_KLCD += 1/2 * einsum('iLCx,KiyD,xy->KLCD', X_abab, v_xxae, rdm_ca, optimize = einsum_type)
    sigma_KLCD += 1/2 * einsum('iLDx,iyCK,xy->KLCD', X_abab, v_xaex, rdm_ca, optimize = einsum_type)
    sigma_KLCD -= einsum('KLDx,C,xC->KLCD', X_baab, e_extern, t1_ae, optimize = einsum_type)
    sigma_KLCD += einsum('KLDx,xy,yC->KLCD', X_baab, h_aa, t1_ae, optimize = einsum_type)
    sigma_KLCD += 1/2 * einsum('KLDx,xyzC,yz->KLCD', X_baab, v_aaae, rdm_ca, optimize = einsum_type)
    sigma_KLCD -= einsum('KLDx,yzxC,zy->KLCD', X_baab, v_aaae, rdm_ca, optimize = einsum_type)
    sigma_KLCD += 1/2 * einsum('KLax,yCaD,xy->KLCD', X_baab, v_aeee, rdm_ca, optimize = einsum_type)
    sigma_KLCD -= 1/2 * einsum('KiCx,iyDL,xy->KLCD', X_baab, v_vaev, rdm_ca, optimize = einsum_type)
    sigma_KLCD -= 1/2 * einsum('KiDx,LiyC,xy->KLCD', X_baab, v_vvae, rdm_ca, optimize = einsum_type)
    sigma_KLCD -= 1/2 * einsum('iLDx,KiyC,xy->KLCD', X_baab, v_xxae, rdm_ca, optimize = einsum_type)
    sigma_KLCD += einsum('iLDx,iyCK,xy->KLCD', X_baab, v_xaex, rdm_ca, optimize = einsum_type)
    sigma_KLCD -= 1/2 * einsum('KLCx,D,xyzD,zy->KLCD', X_abab, e_extern, t1_aaae, rdm_ca, optimize = einsum_type)
    sigma_KLCD += einsum('KLCx,D,yxzD,zy->KLCD', X_abab, e_extern, t1_aaae, rdm_ca, optimize = einsum_type)
    sigma_KLCD += 1/2 * einsum('KLCx,xy,yzwD,wz->KLCD', X_abab, h_aa, t1_aaae, rdm_ca, optimize = einsum_type)
    sigma_KLCD -= einsum('KLCx,xy,zywD,wz->KLCD', X_abab, h_aa, t1_aaae, rdm_ca, optimize = einsum_type)
    sigma_KLCD += einsum('KLCx,yz,wxyD,zw->KLCD', X_abab, h_aa, t1_aaae, rdm_ca, optimize = einsum_type)
    sigma_KLCD -= 1/2 * einsum('KLCx,yz,xwyD,zw->KLCD', X_abab, h_aa, t1_aaae, rdm_ca, optimize = einsum_type)
    sigma_KLCD += 1/2 * einsum('KLCx,yz,xywD,zw->KLCD', X_abab, h_aa, t1_aaae, rdm_ca, optimize = einsum_type)
    sigma_KLCD -= einsum('KLCx,yz,yxwD,zw->KLCD', X_abab, h_aa, t1_aaae, rdm_ca, optimize = einsum_type)
    sigma_KLCD += 1/2 * einsum('KLCx,xyzD,ywuv,zuwv->KLCD', X_abab, t1_aaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLCD -= 1/2 * einsum('KLCx,xyzD,zwuv,yuwv->KLCD', X_abab, t1_aaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLCD -= einsum('KLCx,yD,xyzw,zw->KLCD', X_abab, t1_ae, v_aaaa, rdm_ca, optimize = einsum_type)
    sigma_KLCD += 1/2 * einsum('KLCx,yD,xzwy,wz->KLCD', X_abab, t1_ae, v_aaaa, rdm_ca, optimize = einsum_type)
    sigma_KLCD -= einsum('KLCx,yxzD,ywuv,zuwv->KLCD', X_abab, t1_aaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLCD += einsum('KLCx,yxzD,zwuv,yuwv->KLCD', X_abab, t1_aaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLCD += 1/2 * einsum('KLCx,yzwD,xuvy,wuvz->KLCD', X_abab, t1_aaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLCD += 1/2 * einsum('KLCx,yzwD,xuvz,wuyv->KLCD', X_abab, t1_aaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLCD -= 1/2 * einsum('KLCx,yzwD,xuwv,zyuv->KLCD', X_abab, t1_aaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLCD += 1/2 * einsum('KLCx,yzwD,xyuv,wvzu->KLCD', X_abab, t1_aaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLCD += 1/2 * einsum('KLCx,yzwD,xyuz,wu->KLCD', X_abab, t1_aaae, v_aaaa, rdm_ca, optimize = einsum_type)
    sigma_KLCD -= einsum('KLCx,yzwD,xzuv,wvyu->KLCD', X_abab, t1_aaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLCD -= einsum('KLCx,yzwD,xzuy,wu->KLCD', X_abab, t1_aaae, v_aaaa, rdm_ca, optimize = einsum_type)
    sigma_KLCD += 1/2 * einsum('KLDx,C,xyzC,zy->KLCD', X_baab, e_extern, t1_aaae, rdm_ca, optimize = einsum_type)
    sigma_KLCD -= einsum('KLDx,C,yxzC,zy->KLCD', X_baab, e_extern, t1_aaae, rdm_ca, optimize = einsum_type)
    sigma_KLCD -= 1/2 * einsum('KLDx,xy,yzwC,wz->KLCD', X_baab, h_aa, t1_aaae, rdm_ca, optimize = einsum_type)
    sigma_KLCD += einsum('KLDx,xy,zywC,wz->KLCD', X_baab, h_aa, t1_aaae, rdm_ca, optimize = einsum_type)
    sigma_KLCD -= einsum('KLDx,yz,wxyC,zw->KLCD', X_baab, h_aa, t1_aaae, rdm_ca, optimize = einsum_type)
    sigma_KLCD += 1/2 * einsum('KLDx,yz,xwyC,zw->KLCD', X_baab, h_aa, t1_aaae, rdm_ca, optimize = einsum_type)
    sigma_KLCD -= 1/2 * einsum('KLDx,yz,xywC,zw->KLCD', X_baab, h_aa, t1_aaae, rdm_ca, optimize = einsum_type)
    sigma_KLCD += einsum('KLDx,yz,yxwC,zw->KLCD', X_baab, h_aa, t1_aaae, rdm_ca, optimize = einsum_type)
    sigma_KLCD -= 1/2 * einsum('KLDx,xyzC,ywuv,zuwv->KLCD', X_baab, t1_aaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLCD += 1/2 * einsum('KLDx,xyzC,zwuv,yuwv->KLCD', X_baab, t1_aaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLCD += einsum('KLDx,yC,xyzw,zw->KLCD', X_baab, t1_ae, v_aaaa, rdm_ca, optimize = einsum_type)
    sigma_KLCD -= 1/2 * einsum('KLDx,yC,xzwy,wz->KLCD', X_baab, t1_ae, v_aaaa, rdm_ca, optimize = einsum_type)
    sigma_KLCD += einsum('KLDx,yxzC,ywuv,zuwv->KLCD', X_baab, t1_aaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLCD -= einsum('KLDx,yxzC,zwuv,yuwv->KLCD', X_baab, t1_aaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLCD -= 1/2 * einsum('KLDx,yzwC,xuvy,wuvz->KLCD', X_baab, t1_aaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLCD -= 1/2 * einsum('KLDx,yzwC,xuvz,wuyv->KLCD', X_baab, t1_aaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLCD += 1/2 * einsum('KLDx,yzwC,xuwv,zyuv->KLCD', X_baab, t1_aaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLCD -= 1/2 * einsum('KLDx,yzwC,xyuv,wvzu->KLCD', X_baab, t1_aaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLCD -= 1/2 * einsum('KLDx,yzwC,xyuz,wu->KLCD', X_baab, t1_aaae, v_aaaa, rdm_ca, optimize = einsum_type)
    sigma_KLCD += einsum('KLDx,yzwC,xzuv,wvyu->KLCD', X_baab, t1_aaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLCD += einsum('KLDx,yzwC,xzuy,wu->KLCD', X_baab, t1_aaae, v_aaaa, rdm_ca, optimize = einsum_type)
    sigma[cvee] += ascontiguousarray(sigma_KLCD).reshape(-1)

    mr_adc.log.timer_debug("computing sigma H1 h1-h1 CVEE-CVEA", *cput1)

def compute_sigma_vector__H1__h1_h1__CVEE_CVEA__V_AEEE(mr_adc, X_abab, X_baab, sigma, v_aeee):        
    cput1 = (logger.process_clock(), logger.perf_counter())

    # Einsum definition from kernel
    einsum = mr_adc.interface.einsum
    einsum_type = mr_adc.interface.einsum_type

    #Excitation Manifold
    cvee = mr_adc.h1.cvee

    # Reduced Density Matrices
    rdm_ca = mr_adc.rdm.ca

    sigma_KLCD  = einsum('KLax,xDaC->KLCD', X_abab, v_aeee, optimize = einsum_type)
    sigma_KLCD -= einsum('KLax,xCaD->KLCD', X_baab, v_aeee, optimize = einsum_type)
    sigma_KLCD -= 1/2 * einsum('KLax,yDaC,xy->KLCD', X_abab, v_aeee, rdm_ca, optimize = einsum_type)
    sigma_KLCD += 1/2 * einsum('KLax,yCaD,xy->KLCD', X_baab, v_aeee, rdm_ca, optimize = einsum_type)
    sigma[cvee] += ascontiguousarray(sigma_KLCD).reshape(-1)

    mr_adc.log.timer_debug("contracting v2e.aeee", *cput1)
    
